<?php $__env->startSection('content'); ?><div class="table-card"><div class="d-flex justify-content-between"><div><h2>LocalMart BD</h2><p>Bangla-friendly Invoice</p></div><button class="btn btn-primary no-print" data-print>Print</button></div><hr><p><strong>Invoice:</strong> <?php echo e($order->order_number); ?> | <strong>Date:</strong> <?php echo e($order->created_at->format('d M Y')); ?></p><p><strong>Customer:</strong> <?php echo e($order->shippingAddress->name); ?> | <?php echo e($order->shippingAddress->phone); ?> | <?php echo e($order->shippingAddress->email); ?></p><p><strong>Address:</strong> <?php echo e($order->shippingAddress->address_line); ?>, <?php echo e($order->shippingAddress->city); ?>, <?php echo e($order->shippingAddress->district); ?></p><table class="table"><tr><th>Product</th><th>Qty</th><th>Price</th><th>Total</th></tr><?php $__currentLoopData = $order->items; $__env->addLoop($__currentLoopData); foreach($__currentLoopData as $item): $__env->incrementLoopIndices(); $loop = $__env->getLastLoop(); ?><tr><td><?php echo e($item->product_name); ?></td><td><?php echo e($item->quantity); ?></td><td>৳<?php echo e(number_format($item->unit_price,2)); ?></td><td>৳<?php echo e(number_format($item->total_price,2)); ?></td></tr><?php endforeach; $__env->popLoop(); $loop = $__env->getLastLoop(); ?></table><div class="text-end"><p>Subtotal: ৳<?php echo e(number_format($order->subtotal,2)); ?></p><p>Delivery: ৳<?php echo e(number_format($order->delivery_charge,2)); ?></p><p>Discount: ৳<?php echo e(number_format($order->discount_amount,2)); ?></p><h3>Total: ৳<?php echo e(number_format($order->total_amount,2)); ?></h3><p>Payment: <?php echo e(str_replace('_',' ',$order->payment->method)); ?> / <?php echo e($order->payment->status); ?></p></div></div><?php $__env->stopSection(); ?>

